    const counts = Array.from(freq.values());
    let S = 0;
    let S2 = 0;

    for (const count of counts) {
        const term = (count * (count - 1)) >> 1;
        S = (S + term) % MOD;
        const term_sq = (term * term) % MOD;
        S2 = (S2 + term_sq) % MOD;
